@ARTICLE{10.3390/nu18030401,
	author = {He X and Liu Y and Cui S and Yu Z and He Z and Zong Y and Chen W and Geng J and Zhou J and Li Z and Zhao Y and Teng H},
	title = {Research on the Therapeutic Effect and Mechanism of Stir-Roasted Deer Velvet Antler with Ghee on Non-Alcoholic Fatty Liver Disease.},
	journal = {Nutrients},
	year = {2026},
	abstract = {Objectives: This study aims to explore the therapeutic effect and mechanism of stir-roasted deer velvet antler with ghee (ZLR) on Non-Alcoholic Fatty Liver Disease (NAFLD). Methods: This study used proteomics to analyze the protein composition of roasted deer antler velvet. It established a high-fat diet (HFD)-induced NAFLD rat model and evaluated the therapeutic effects of different dosage groups, including liver injury, oxidative stress, glucose metabolism, steatosis, and insulin homeostasis (via fasting glucose tolerance). Transcriptomics explored the mechanism. Gene expression and Western blot detected lipid metabolism-related gene expression. In vivo experiments validated that ZLR-containing serum alleviates NAFLD and reduces reactive oxygen species levels. Results: The results indicated that ZLR could significantly reduce the body weight, liver weight and degree of hepatic steatosis in HFD rats, improve glycolipid metabolism and insulin sensitivity, and alleviate oxidative stress damage. The mechanism involves activating the adenosine monophosphate-activated protein kinase/peroxisome proliferator-activated receptor (AMPK/PPAR) signaling pathway, regulating the expression of lipid metabolism-related genes, promoting fatty acid oxidation, and reducing fat deposition. The results of in vitro experiments show that ZLR-containing serum can effectively reduce lipid droplet production in liver cells and effectively alleviate oxidative stress damage in liver cells. Conclusions: The traditional Chinese medicine processed product ZLR can regulate lipid metabolism in the body and alleviate the degree of NAFLD by activating the AMPK and PPAR signaling pathways. It provides new ideas for the clinical treatment of NAFLD.},
	doi = {10.3390/nu18030401},
	pmid = {41683224 [Indexed for MEDLINE]},
	note = {PMC12899000}
}

@ARTICLE{10.1016/j.phymed.2026.157922,
	author = {Wu J and Liu S and Ma Z and Munkhbayar B and Liao Q and Hou M and Wei Y and Xiao Y and Wang Y and Chen R and Batsaikhan B and Batchuluun K and Zhou L and Li Y},
	title = {Aloesin improves metabolic associated fatty liver disease and obesity by targeting TGFBR1.},
	journal = {Phytomedicine},
	year = {2026},
	abstract = {BACKGROUND: Metabolic associated fatty liver disease (MAFLD) is a chronic liver condition with a high global prevalence. Obesity and its associated insulin resistance are among the main risk factors for MAFLD, for which no effective clinical treatments are currently available. Aloesin, a natural chromone compound derived from Aloe vera, has anti-inflammatory, antioxidant, anticancer, and antidiabetes activity. However, its involvement in MAFLD has not been systematically studied. PURPOSE: This study investigated the effectiveness of aloesin against MAFLD and obesity and elucidated its potential molecular mechanism. METHODS: Aloesin was added to the high-fat diet-of an induced mouse model and to oleic acid/palmitic acid-induced HepG2 cells to explore its effect on lipid metabolism. Molecular targets were identified by reverse docking, cellular thermal shift assay (CETSA), and drug affinity responsive target stability (DARTS). RESULTS: Aloesin significantly reduced lipid accumulation in hepatocytes in both the high-fat diet-induced MAFLD mouse model and the oleic acid/palmitic acid-induced HepG2 cells. It also alleviated oxidative stress and energy metabolism disorders and decreased the body fat mass in mice fed the high-fat diet, which ameliorated the pathological features of MAFLD and obesity. Target prediction and validation identified TGFBR1 as a direct target of aloesin, which was confirmed by CETSA and DARTS. Functional experiments demonstrated that overexpression of TGFBR1 increased lipid accumulation and metabolic disturbances, which were reversed by aloesin. CONCLUSION: Aloesin improved lipid deposition and slowed the progression of MAFLD by targeting TGFBR1. The results support its potential application for the prevention and treatment of MAFLD.},
	doi = {10.1016/j.phymed.2026.157922},
	pmid = {41678914 [Indexed for MEDLINE]}
}

@ARTICLE{10.1152/japplphysiol.00939.2025,
	author = {Claiborne A and Jevtovic F and Biagioni EM and Rossa L and Ollmann C and Zheng D and Strom C and Wisseman B and McDonald S and Newton E and Mouro S, deVente J and Kelley GA and Houmard JA and Broskey NT and May LE},
	title = {Exercise FITT-V during pregnancy: dose-dependent reduction in infant cellular lipid content and whole body fat.},
	journal = {J Appl Physiol (1985)},
	year = {1985},
	abstract = {Modifiable health behaviors such as exercise regulate adiposity in adults, but the effects of exercise during pregnancy on infant adiposity remain understudied. This report analyzed the relationship between prenatal exercise frequency, intensity, time, type, and volume (FITT-V) and infant adiposity, to better guide prenatal exercise prescription. Female participants [body mass index = 29.0 kg/m2, 30.5 yr of age, with gravida = 1 and parity = 0, peak oxygen consumption (V̇o2peak) = 21.9 mL/kg/min, and pregnant for 39.6 wk] were randomized to supervised exercise (aerobic, resistance, combination) or attention control for ∼24 wk during pregnancy. FITT-V metrics were analyzed from session records. Infant mesenchymal stem cells (MSCs), a model of infant adiposity, were collected from umbilical cord at delivery, adipogenically differentiated, and stained for lipids. Infant body fat percentage was estimated from skinfolds measured at 1 mo of age. Higher weekly exercise volume correlated with lower infant body fat (R2 = 0.12, P = 0.03) and MSC lipids (R2 = 0.13, P = 0.01). Weekly exercise frequency (R2 = 0.06, P = 0.10) and total volume (R2 = 0.19, P = 0.002) influenced adiposity. Subscapular skinfolds were notably affected by exercise (R2 = 0.27, P < 0.001). We conclude that in utero exposure to exercise beyond minimum recommendations is associated with reduced infant adiposity. Specifically, our findings suggest that exercising below 450 metabolic equivalent (MET)·min/wk, e.g., exercising at an average of 3 METs for 150 min/wk or 5 METs for 90 min/wk, excludes individuals from these offspring health benefits.NEW & NOTEWORTHY This study was the first to test how specific prenatal exercise dose, i.e., the FITT-V (frequency, intensity, time, type, volume) metrics, could influence the storage of triglycerides in infant adipogenic mesenchymal stem cells (MSCs). Prenatal exercise led to a reduction in infant whole body fat percentage (BF%), which was reflected by lower lipid storage in infant MSCs. Changes in lipid content were observed in offspring born to participants exercising beyond the minimum recommended weekly volume, 450 metabolic equivalent (MET)·min/wk.},
	doi = {10.1152/japplphysiol.00939.2025},
	pmid = {41665099 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.intimp.2026.116320,
	author = {Feng C and Liu Q and Peng J and Jia C and Pan X and Liu S and Geng X and Zhai J and Wu M and Hao S and Lei L and Xu K and Ma Y and Lei L and Liu Z and Huan Y and Shen Z},
	title = {The novel SPPARM YR3-16 ameliorates metabolic disorders in vivo and attenuates adipocyte inflammation in vitro via PPARγ-dependent ERK suppression.},
	journal = {Int Immunopharmacol},
	year = {2026},
	abstract = {Obesity-related metabolic disorders and adipocyte inflammation are key drivers of type 2 diabetes, but conventional therapies remain suboptimal in addressing these core pathologies. This study aimed to characterize YR3-16 as a novel selective peroxisome proliferator-activated receptor γ modulator (SPPARM) with efficacy in improving metabolic homeostasis and reducing adipocyte inflammation. YR3-16 is a novel tetrahydroisoquinoline derivative that selectively activates PPARγ and exhibits a binding mode distinct from that of pioglitazone. In spontaneous obese and type 2 diabetic KKAy mice, oral administration of YR3-16 (three doses, 25/50/75 mg/kg) for 30 days dose-dependently ameliorated metabolic disorders: it improved insulin sensitivity (insulin tolerance test), and reduced plasma triglycerides, free fatty acids and total cholesterol. Consistent results were also observed in diet-induced obese (DIO) mice. In 3 T3-L1 adipocytes, YR3-16 (10 μM) reprogrammed lipid metabolism at the gene transcriptional level, and suppressed pro-inflammatory cytokine secretion (tumor necrosis factor-α (TNF-α), interleukin-1β (IL-1β)), associated with the inhibition of extracellular signal-regulated kinase (ERK) signaling pathway, which was abolished by the peroxisome proliferator-activated receptor γ antagonist GW9662. YR3-16, as a novel SPPARM, concurrently improves metabolic disorders in vivo and attenuates adipocyte inflammation via peroxisome proliferator-activated receptor γ activation, highlighting its potential for treating obesity-related diseases.},
	doi = {10.1016/j.intimp.2026.116320},
	pmid = {41662813 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s10695-026-01653-9,
	author = {Wang B and Zheng H and Xiong J and Yang HJ and Li QL and Luo Z},
	title = {Lecithin supplementation to HFD improves largemouth bass liver health: Implications for regulating lipid homeostasis, antioxidant responses and endoplasmic reticulum stress.},
	journal = {Fish Physiol Biochem},
	year = {2026},
	abstract = {Dietary lipids serve as economical energy sources in aquaculture feeds. Elevating lipid content promotes protein conservation and mitigates nitrogen waste. Fish health, however, can be severely impacted by fatty liver resulting from prolonged high-fat diet (HFD) feeding. Adding lecithin to the feed might be a potential improvement solution. This study investigated how dietary lipid and phospholipid levels affect hepatic lipid homeostasis, endoplasmic reticulum (ER) stress, and redox balance in largemouth bass. Five diets were formulated: a control (10.67% lipid, no added lecithin), a normal-lipid diet with 1.0 g/kg lecithin, the HFD (18.65% lipid, no added lecithin), and the HFD supplemented with either 1.0 or 2.0 g/kg lecithin (HFD + lecithin 1, HFD + lecithin 2). Lecithin supplementation reversed HFD-induced intrahepatic fat deposition while mitigating the decline in hepatic polyunsaturated fatty acids content. Lecithin supplementation mitigated HFD-stimulated increases in hepatic triglyceride, total cholesterol, key lipogenic enzyme activities, and mRNA levels of lipogenic genes/transcription factors. Furthermore, lecithin lessened the impact of HFD on hepatic very low density lipoprotein (VLDL), preventing both a lessened VLDL content and diminished VLDL secretion. Regarding ER stress and antioxidant responses: dietary lecithin addition alleviated HFD-induced increment of mRNA levels of ER stress markers and MDA content, and mitigated HFD-induced reduction of hepatic total superoxide dismutase, catalase, and total antioxidant capacity. This demonstrates lecithin's protective role against HFD-induced hepatic injury by restoring lipid homeostasis, alleviating ER stress, and strengthening antioxidant capacity.},
	doi = {10.1007/s10695-026-01653-9},
	pmid = {41661360 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.molmet.2026.102330,
	author = {Su Y and Li X and Wang Y and Lu X and Ye Y and Sun J and Liu T and Cai J and Ma X and Yang Y and Zhou J},
	title = {ANKRD53 is downregulated in human obesity and coordinates lipolysis with mitochondrial oxidative metabolism in adipocytes.},
	abstract = {AIMS: Human adipose tissue is central to obesity-associated metabolic dysfunction. ANKRD53 is a human-specific, adipocyte-enriched ankyrin repeat scaffold protein with largely unknown function. We investigated its role in human adipocyte metabolism and the underlying mechanism. METHODS: RNA-seq analysis of subcutaneous adipose tissue (SAT) and visceral adipose tissue (VAT) from 236 individuals quantified ANKRD53 expression and its association with metabolic traits. In human primary adipocytes, we assessed lipolysis (free fatty acid and glycerol release) and mitochondrial respiration (oxygen consumption rate) after ANKRD53 overexpression or knockdown. An AAV was used to overexpress ANKRD53 in mouse inguinal white adipose tissue (iWAT). Protein interactors were identified by immunoprecipitation-mass spectrometry, and knockdown experiments confirmed a functional role of ACSL1. RESULTS: ANKRD53 expression in both adipose depots was markedly reduced in obesity and inversely correlated with BMI, adiposity measures, insulin resistance indices, and circulating triglycerides, while positively associated with adiponectin and HDLc. In human adipocytes, ANKRD53 overexpression enhanced forskolin-stimulated lipolysis and mitochondrial respiration, whereas silencing impaired these processes. Adipose-targeted ANKRD53 overexpression in mice increased lipolysis in vivo. Mechanistically, ANKRD53 interacted with ACSL1 and promoted its mitochondrial localization, channeling lipolysis-derived FFAs into β-oxidation; silencing ACSL1 abrogated ANKRD53's effects. CONCLUSIONS: ANKRD53 is reduced in obesity and coordinates lipolysis with mitochondrial oxidative metabolism in human adipocytes, promoting efficient use of lipolysis-derived FFAs via ACSL1. These findings establish ANKRD53 as a key regulator of adipocyte energy metabolism and a potential therapeutic target for improving metabolic health in obesity.},
	doi = {10.1016/j.molmet.2026.102330},
	pmid = {41654016 [Indexed for MEDLINE]},
	note = {PMC12924745}
}

@ARTICLE{10.1016/j.foodres.2025.118175,
	author = {Zhang Y and Zeng W and Liu Y and Wang X},
	title = {Pine nut oil as a functional alternative to corn oil: Process selection, provenance profiling, and multi-omics evidence of lipid-lowering efficacy in Western-diet mice.},
	journal = {Food Res Int},
	year = {2026},
	abstract = {Pine nut oil (PNO) is a candidate alternative to corn oil (CO) owing to comparable unsaturated fatty-acid profiles and enrichment in pinolenic acid (Δ5-18:3) and lipid-soluble micronutrients. We systematically compared extraction routes (solvent, supercritical CO2, pressing), established solvent extraction as the optimal balance of yield and bioactive retention, and then characterized solvent-extracted oils from eight provenances using a weighted composite score to nominate Pinus tabuliformis for in vivo testing. In diet-induced obese mice (12-week Western diet, then 12-week intervention, n = 10 per group), replacing CO with PNO lowered body-mass gain and liver weight and improved serum lipids (triglycerides ↓ ∼ 28 %, total cholesterol ↓ ∼ 15 %, LDL-C ↓ ∼ 20 %) without affecting HDL-C or glucose; ALT and AST fell by ∼30 %, indicating hepatoprotection. Hepatic multi-omics revealed coherent remodeling toward PUFA-rich phospholipid species, activation of PPAR-centered peroxisomal/mitochondrial fatty-acid degradation and circadian pathways, and integrative correlations implicating Cyp4a10/14, Ehhadh, Slc27a2, Fgf21, Angptl4, and Plin5. Collectively, PNO reoriented hepatic lipid flux toward oxidation and membrane remodeling, supporting its development as a nutritionally advantaged culinary oil.},
	doi = {10.1016/j.foodres.2025.118175},
	pmid = {41652743 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.foodres.2025.118284,
	author = {Li Z and Yao Y and Han H and Cao Q and Tang B and Liu Y and Zhou Z and Zhang W},
	title = {Bioactive polymethoxylated flavones from Clerodendranthus spicatus alleviate high-fat diet-induced lipid dysfunction and metabolic inflammation via targeting the PPARα/NF-κB pathway.},
	journal = {Food Res Int},
	year = {2026},
	abstract = {The high-fat diet (HFD) pattern is currently a major cause of chronic metabolic diseases worldwide, especially metabolic dysfunction-associated steatohepatitis (MASH). Clerodendranthus spicatus (Thunb.) C. Y. Wu (CST) is an edible-medicinal plant widely used for health promotion, however its bioactive constituents and mechanisms against HFD-induced metabolic disorders have not been convincingly demonstrated. In this study, the ethyl acetate fraction of CST extract (EAF_CST), rich in polymethoxylated flavones (PMFs), showed better lipid-lowering and anti-inflammatory activities than raw extract. Subsequent in vivo experiments confirmed that EAF_CST markedly alleviated HFD-induced obesity (body weight reduced by 17% in the high-dose group, p < 0.001 vs. HFD), insulin resistance, dyslipidemia (serum TG lowered by 40% in the high-dose group, p < 0.001 vs. HFD), hepatic steatosis and inflammation in rats. Further integrative transcriptomic and network analysis revealed that tetramethylscutellarein, trimethylapigenin and eupatorin-5-methylether strongly interacted with lipid/inflammation-related hub targets and pathways (notably the PPAR signaling pathway), leading to their designation as the core bioactive constituents. Geographical commonality and efficacy validation further reinforced this designation. Mechanistically, these PMFs directly bound to PPARα, thereby enabling EAF_CST to promote fatty acid oxidation, and suppress NF-κB-mediated inflammatory response. Finally, the therapeutic effects of EAF_CST were further verified to depend on PPARα. This study establishes a clear constituent-target-pathway axis for CST's metabolic benefits, and the first evidence that these benefits are mediated by the core PMFs targeting PPARα. These findings also provide a scientific basis for developing CST into functional foods/nutraceuticals for combating HFD-related disorders (e.g., MASH).},
	doi = {10.1016/j.foodres.2025.118284},
	pmid = {41652694 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.bbadis.2026.168186,
	author = {Zhang K and Kan C and Qiu H and Shi J and Chen J and Zheng T and Zhang J and Ma Y and Sheng S and Hou N and Han F and Sun X},
	title = {12,13-diHOME ameliorates MASLD by regulating Sestrin2-mediated AMPK/ULK1/Lipophagy in obese mice.},
	journal = {Biochim Biophys Acta Mol Basis Dis},
	year = {2026},
	abstract = {Obesity-driven metabolic dysfunction-associated steatotic liver disease (MASLD) is characterized by hepatic lipid accumulation and impaired lipid metabolism. Enhancing lipophagy, the autophagic degradation of lipid droplets, represents a promising therapeutic strategy. Sestrin2, a stress-responsive protein, promotes lipophagy via the AMPK/ULK1 pathway. Here, we investigated the role of 12,13-diHOME, a brown adipose tissue-derived lipid, in modulating MASLD via Sestrin2. Male Sesn2 knockout and wild-type mice were fed a high-fat diet (HFD) and treated with 12,13-diHOME. Metabolic parameters, liver histology, and lipophagy-related protein expression were analyzed. 12,13-diHOME improved insulin sensitivity, reduced plasma triglycerides and free fatty acids, and alleviated hepatic steatosis and fibrosis by enhancing lipophagy in wild-type mice. Mechanistically, 12,13-diHOME increased Sestrin2 expression, activated AMPK/ULK1 signaling, inhibited mTOR phosphorylation, and enhanced lipophagic degradation of lipid droplets. These effects were abolished in Sesn2-deficient mice and cells, demonstrating that Sestrin2 is essential for 12,13-diHOME's protective actions. Our findings identify 12,13-diHOME as a potential therapeutic agent for MASLD via Sestrin2-mediated lipophagy.},
	doi = {10.1016/j.bbadis.2026.168186},
	pmid = {41650585 [Indexed for MEDLINE]}
}

@ARTICLE{10.1186/s40168-026-02343-7,
	author = {Li C and Liu G and Yang Y and Shi Z and Shao Q and Fang Z and Song Y and Gao W and Lei L and Du X and Li X},
	title = {Altered rumen bacterial flora is associated with increased lipogenesis of adipose tissue in obese dairy cows before calving.},
	journal = {Microbiome},
	year = {2026},
	abstract = {BACKGROUND: Prepartum obesity predisposes dairy cows to a higher risk of postpartum metabolic disorder. Volatile fatty acids (VFA) produced through ruminal microbial fermentation of feed substrates serve as a key form of energy for dairy cows. However, the precise mechanisms through which the rumen microbiota promote adipocyte lipid accumulation in obese dairy cows remain to be elucidated. Thus, the aim of this study was to investigate the mechanisms by which rumen microbiota regulates prepartum obesity in dairy cows. RESULTS: Plasma glucose, insulin, triglyceride, and free fatty acids were greater in obese dairy cows. In the adipose tissue, the triglyceride content and expression of genes involved in lipid synthesis were higher in obese dairy cows. In the liver, the expression of genes involved in gluconeogenesis and lipid synthesis was higher in obese dairy cows. The ruminal total VFA, acetate, and propionate were higher in obese dairy cows compared to normal cows. The 16S rRNA gene analysis revealed that rumen bacteria, including Tidjanibacter inops_A, Rikenella massiliensis, Papillibacter cinnamivorans, and Parabacteroides merdae, were enriched in the rumen of obese dairy cows. Enrichment of these bacteria promoted carbohydrate degradation and VFA production. The metabolome analysis showed that obese dairy cows had elevated citric acid level in the rumen, which was positively associated with body condition score, body weight, adipocyte diameter, ruminal VFA concentration, and the abundance of VFA-producing bacteria. CONCLUSIONS: Our results suggest that rumen bacterial flora in prepartum obese dairy cows supply more VFA to the host, which may induce lipid deposition in adipocytes. Video Abstract.},
	doi = {10.1186/s40168-026-02343-7},
	pmid = {41645262 [Indexed for MEDLINE]},
	note = {PMC12895798}
}
